def page_data_explorer() -> None:
    section_header("EDA", "Data Explorer", "Filter and visualize the customer base interactively.")

    df = get_active_dataset()
    cat_cols = [c for c in df.select_dtypes(include=["object", "category"]).columns if c not in [ID_COL]]
    num_cols = df.select_dtypes(include=[np.number]).columns.tolist()

    with st.container():
        f1, f2, f3 = st.columns(3)
        contract_f = f1.multiselect("Contract", sorted(df["Contract"].unique()) if "Contract" in df.columns else [])
        internet_f = f2.multiselect("Internet Service", sorted(df["InternetService"].unique()) if "InternetService" in df.columns else [])
        gender_f = f3.multiselect("Gender", sorted(df["gender"].unique()) if "gender" in df.columns else [])

    view_df = df.copy()
    if contract_f:
        view_df = view_df[view_df["Contract"].isin(contract_f)]
    if internet_f:
        view_df = view_df[view_df["InternetService"].isin(internet_f)]
    if gender_f:
        view_df = view_df[view_df["gender"].isin(gender_f)]

    st.caption(f"Showing {len(view_df):,} of {len(df):,} customers")

    c1, c2 = st.columns(2)
    x_axis = c1.selectbox("X-axis", cat_cols + num_cols)
    chart_type = c2.selectbox("Chart type", ["Histogram", "Bar (counts)", "Box vs Churn", "Scatter"])

    st.markdown('<div class="glass-card">', unsafe_allow_html=True)
    try:
        if chart_type == "Histogram" and x_axis in num_cols:
            fig = px.histogram(view_df, x=x_axis, color=TARGET if TARGET in view_df.columns else None,
                                color_discrete_sequence=[BRAND_SEQ[0], BRAND_SEQ[4]])
        elif chart_type == "Bar (counts)":
            counts = view_df[x_axis].value_counts().reset_index()
            counts.columns = [x_axis, "Count"]
            fig = px.bar(counts, x=x_axis, y="Count", color=x_axis, color_discrete_sequence=BRAND_SEQ)
        elif chart_type == "Box vs Churn" and x_axis in num_cols:
            fig = px.box(view_df, x=TARGET, y=x_axis, color=TARGET,
                         color_discrete_sequence=[BRAND_SEQ[0], BRAND_SEQ[4]])
        else:
            y_axis = num_cols[1] if len(num_cols) > 1 else num_cols[0]
            fig = px.scatter(view_df, x=x_axis if x_axis in num_cols else num_cols[0], y=y_axis,
                              color=TARGET if TARGET in view_df.columns else None,
                              color_discrete_sequence=[BRAND_SEQ[0], BRAND_SEQ[4]])
        fig.update_layout(**PLOTLY_DARK, height=420)
        st.plotly_chart(fig, use_container_width=True)
    except Exception as e:
        st.error(f"Could not render chart: {e}")
    st.markdown("</div>", unsafe_allow_html=True)

    if len(num_cols) >= 2:
        st.write("")
        st.markdown('<div class="glass-card">', unsafe_allow_html=True)
        st.markdown("**Correlation Heatmap (numeric features)**")
        corr = view_df[num_cols].corr()
        fig_hm = px.imshow(corr, text_auto=".2f", color_continuous_scale="Tealrose", aspect="auto")
        fig_hm.update_layout(**PLOTLY_DARK, height=400)
        st.plotly_chart(fig_hm, use_container_width=True)
        st.markdown("</div>", unsafe_allow_html=True)

    with st.expander("📋 Filtered Data Table"):
        st.dataframe(view_df, use_container_width=True)
        st.download_button("⬇️ Download filtered data", view_df.to_csv(index=False).encode("utf-8"),
                            "filtered_telco_data.csv", "text/csv")


