def page_prediction() -> None:
    section_header("MACHINE LEARNING", "Live Churn Prediction", "Score a customer profile in real time using the trained models.")

    df = get_active_dataset()
    if TARGET not in df.columns:
        st.warning("Active dataset needs a 'Churn' column to train a prediction model.", icon="⚠️")
        return

    with st.spinner("Training models on the active dataset..."):
        bundle = train_all_models(df)

    if bundle is None:
        st.error("Model training failed — check that the dataset has both churn classes present.", icon="🚫")
        return

    model_choice = st.selectbox("Model to use for prediction", list(bundle["results"].keys()), index=2)
    model = bundle["results"][model_choice]["model"]
    st.success(f"{model_choice} trained and ready for inference.", icon="✅")

    tab1, tab2 = st.tabs(["🎛️ Manual Prediction", "📄 Batch Prediction"])

    with tab1:
        st.markdown('<div class="glass-card">', unsafe_allow_html=True)
        st.markdown("**Customer Profile**")
        cols = st.columns(3)
        input_values = {}
        for i, feat in enumerate(bundle["features"]):
            col = cols[i % 3]
            if feat in bundle["encoders"]:
                options = list(bundle["encoders"][feat].classes_)
                input_values[feat] = col.selectbox(feat, options)
            else:
                default_val = float(df[feat].mean()) if feat in df.select_dtypes(include=[np.number]).columns else 0.0
                input_values[feat] = col.number_input(feat, value=round(default_val, 2))
        st.markdown("</div>", unsafe_allow_html=True)

        if st.button("🚀 Predict Churn Risk", use_container_width=True):
            encoded_row = {}
            for feat in bundle["features"]:
                if feat in bundle["encoders"]:
                    encoded_row[feat] = bundle["encoders"][feat].transform([input_values[feat]])[0]
                else:
                    encoded_row[feat] = input_values[feat]
            X_new = pd.DataFrame([encoded_row])[bundle["features"]]

            with st.spinner("Scoring customer..."):
                time.sleep(0.3)
                pred = model.predict(X_new)[0]
                proba = model.predict_proba(X_new)[0][1] if hasattr(model, "predict_proba") else float(pred)

            risk_pct = int(round(proba * 100))
            c1, c2 = st.columns([1, 2])
            with c1:
                st.metric("Churn Probability", f"{risk_pct}%")
            with c2:
                st.progress(risk_pct)

            if proba < 0.3:
                st.markdown('<span class="risk-badge risk-low">🟢 Low Risk</span>', unsafe_allow_html=True)
                st.success("This customer is likely to stay.", icon="✅")
            elif proba < 0.6:
                st.markdown('<span class="risk-badge risk-med">🟠 Medium Risk</span>', unsafe_allow_html=True)
                st.warning("This customer shows some churn signals — consider a retention touchpoint.", icon="⚠️")
            else:
                st.markdown('<span class="risk-badge risk-high">🔴 High Risk</span>', unsafe_allow_html=True)
                st.error("This customer is at high risk of churning — proactive outreach recommended.", icon="🚨")
            st.toast("Prediction complete", icon="🔮")

    with tab2:
        st.markdown("Upload a file with the same feature columns to score customers in bulk.")
        batch_file = st.file_uploader("Batch input file", type=["csv", "xlsx"], key="batch")
        if batch_file is not None:
            try:
                batch_df = load_uploaded_file(batch_file)
                missing = [f for f in bundle["features"] if f not in batch_df.columns]
                if missing:
                    st.error(f"Missing required columns: {missing}", icon="🚫")
                else:
                    work = batch_df.copy()
                    for feat in bundle["features"]:
                        if feat in bundle["encoders"]:
                            le = bundle["encoders"][feat]
                            work[feat] = work[feat].astype(str).apply(lambda v: v if v in le.classes_ else le.classes_[0])
                            work[feat] = le.transform(work[feat])
                    proba = model.predict_proba(work[bundle["features"]])[:, 1] if hasattr(model, "predict_proba") else model.predict(work[bundle["features"]])
                    batch_df["Churn_Probability"] = np.round(proba, 3)
                    batch_df["Predicted_Churn"] = np.where(proba >= 0.5, "Yes", "No")
                    st.success(f"Scored {len(batch_df)} customers.", icon="✅")
                    st.dataframe(batch_df, use_container_width=True)
                    st.download_button(
                        "⬇️ Download Predictions CSV",
                        batch_df.to_csv(index=False).encode("utf-8"),
                        "churn_predictions.csv",
                        "text/csv",
                        use_container_width=True,
                    )
            except Exception as e:
                st.error(f"Error processing batch file: {e}", icon="🚫")


