def page_model_performance() -> None:
    section_header("MODEL DIAGNOSTICS", "Model Performance", "How well does the churn model generalize to unseen customers?")

    df = get_active_dataset()
    if TARGET not in df.columns:
        st.warning("Active dataset needs a 'Churn' column to evaluate a model.", icon="⚠️")
        return

    with st.spinner("Evaluating models on the hold-out test set..."):
        bundle = train_all_models(df)

    if bundle is None:
        st.error("Could not evaluate — dataset needs both churn classes present.", icon="🚫")
        return

    model_choice = st.selectbox("Select model", list(bundle["results"].keys()), index=0, key="perf_model")
    res = bundle["results"][model_choice]

    c1, c2, c3, c4 = st.columns(4)
    c1.metric("Accuracy", f"{res['accuracy']:.1%}")
    c2.metric("Precision", f"{res['precision']:.1%}")
    c3.metric("Recall", f"{res['recall']:.1%}")
    c4.metric("F1 Score", f"{res['f1']:.1%}")

    if res["accuracy"] > 0.8:
        st.success("Strong performance — the model reliably separates churners from loyal customers.", icon="✅")
    elif res["accuracy"] > 0.65:
        st.warning("Moderate performance — usable for prioritization, but treat scores with some caution.", icon="⚠️")
    else:
        st.error("Weak performance — consider more features or a different model.", icon="🚫")

    st.write("")
    col_a, col_b = st.columns(2)
    with col_a:
        st.markdown('<div class="glass-card">', unsafe_allow_html=True)
        st.markdown("**Confusion Matrix**")
        cm = confusion_matrix(bundle["y_test"], res["preds"])
        fig = px.imshow(cm, text_auto=True, color_continuous_scale="Blues",
                        labels=dict(x="Predicted", y="Actual", color="Count"),
                        x=["No Churn", "Churn"], y=["No Churn", "Churn"])
        fig.update_layout(**PLOTLY_DARK, height=380)
        st.plotly_chart(fig, use_container_width=True)
        st.markdown("</div>", unsafe_allow_html=True)

    with col_b:
        st.markdown('<div class="glass-card">', unsafe_allow_html=True)
        st.markdown("**ROC Curve**")
        if res["proba"] is not None:
            fpr, tpr, _ = roc_curve(bundle["y_test"], res["proba"])
            roc_auc = auc(fpr, tpr)
            fig2 = go.Figure()
            fig2.add_trace(go.Scatter(x=fpr, y=tpr, mode="lines", name=f"AUC = {roc_auc:.3f}",
                                       line=dict(color=BRAND_SEQ[0], width=3)))
            fig2.add_trace(go.Scatter(x=[0, 1], y=[0, 1], mode="lines", name="Baseline",
                                       line=dict(color=BRAND_SEQ[2], dash="dash")))
            fig2.update_layout(**PLOTLY_DARK, height=380, xaxis_title="False Positive Rate",
                               yaxis_title="True Positive Rate")
            st.plotly_chart(fig2, use_container_width=True)
        else:
            st.info("This model doesn't support probability scores for an ROC curve.")
        st.markdown("</div>", unsafe_allow_html=True)

    if hasattr(res["model"], "feature_importances_"):
        st.write("")
        st.markdown('<div class="glass-card">', unsafe_allow_html=True)
        st.markdown("**Feature Importance**")
        importance = pd.DataFrame({
            "Feature": bundle["features"],
            "Importance": res["model"].feature_importances_,
        }).sort_values("Importance", ascending=True).tail(15)
        fig3 = px.bar(importance, x="Importance", y="Feature", orientation="h",
                      color="Importance", color_continuous_scale=["#DCEBFF", "#3A86FF"])
        fig3.update_layout(**PLOTLY_DARK, height=420)
        st.plotly_chart(fig3, use_container_width=True)
        st.markdown("</div>", unsafe_allow_html=True)

    with st.expander("📎 Original Model Snapshots"):
        g1, g2 = st.columns(2)
        with g1:
            st.markdown("**Confusion Matrix (original run)**")
            safe_image("confusion_matrix.png", icon="🧮", use_container_width=True)
        with g2:
            st.markdown("**ROC Curve (original run)**")
            safe_image("roc_curve.png", icon="📉", use_container_width=True)
        st.markdown("**Feature Importance (original run)**")
        safe_image("feature_importance.png", icon="🎯", use_container_width=True)


