def page_model_comparison() -> None:
    section_header("BENCHMARKING", "Model Comparison", "Logistic Regression vs Decision Tree vs Random Forest.")

    df = get_active_dataset()
    if TARGET not in df.columns:
        st.warning("Active dataset needs a 'Churn' column to compare models.", icon="⚠️")
        return

    with st.spinner("Training and benchmarking all models..."):
        bundle = train_all_models(df)

    if bundle is None:
        st.error("Could not train models on this dataset.", icon="🚫")
        return

    comp_df = pd.DataFrame([
        {"Model": name, "Accuracy": r["accuracy"], "Precision": r["precision"],
         "Recall": r["recall"], "F1 Score": r["f1"]}
        for name, r in bundle["results"].items()
    ])

    best_model = comp_df.sort_values("Accuracy", ascending=False).iloc[0]
    c1, c2, c3 = st.columns(3)
    c1.metric("Best Model", best_model["Model"])
    c2.metric("Best Accuracy", f"{best_model['Accuracy']:.1%}")
    c3.metric("Models Benchmarked", f"{len(comp_df)}")

    st.write("")
    col_a, col_b = st.columns([3, 2])
    with col_a:
        st.markdown('<div class="glass-card">', unsafe_allow_html=True)
        st.markdown("**Accuracy by Model**")
        fig = px.bar(comp_df, x="Model", y="Accuracy", color="Model", text_auto=".2%",
                    color_discrete_sequence=BRAND_SEQ, range_y=[0, 1])
        fig.update_layout(**PLOTLY_DARK, height=380, showlegend=False)
        st.plotly_chart(fig, use_container_width=True)
        st.markdown("</div>", unsafe_allow_html=True)

    with col_b:
        st.markdown('<div class="glass-card">', unsafe_allow_html=True)
        st.markdown("**Metrics Table**")
        st.dataframe(comp_df.set_index("Model").style.format("{:.1%}"), use_container_width=True)
        st.markdown("</div>", unsafe_allow_html=True)

    st.write("")
    st.markdown('<div class="glass-card">', unsafe_allow_html=True)
    st.markdown("**Multi-metric Comparison**")
    melted = comp_df.melt(id_vars="Model", var_name="Metric", value_name="Score")
    fig2 = px.bar(melted, x="Metric", y="Score", color="Model", barmode="group",
                 color_discrete_sequence=BRAND_SEQ, range_y=[0, 1])
    fig2.update_layout(**PLOTLY_DARK, height=380)
    st.plotly_chart(fig2, use_container_width=True)
    st.markdown("</div>", unsafe_allow_html=True)

    with st.expander("📎 Original Model Comparison Snapshot"):
        safe_image("model_comparison.png", icon="🏆", use_container_width=True)


# =============================================================================
# 14. PAGE — BUSINESS INSIGHTS
# =============================================================================
def page_business_insights() -> None:
    section_header("STRATEGY", "Business Insights", "Translating churn patterns into retention actions.")

    df = get_active_dataset()
    if TARGET not in df.columns:
        st.info("Upload a Telco-schema dataset with a 'Churn' column to unlock tailored insights.")
        return

    churn_rate = (df[TARGET] == "Yes").mean() * 100
    mtm_churn = (df[df["Contract"] == "Month-to-month"][TARGET] == "Yes").mean() * 100 if "Contract" in df.columns else None
    two_yr_churn = (df[df["Contract"] == "Two year"][TARGET] == "Yes").mean() * 100 if "Contract" in df.columns else None
    fiber_churn = (df[df["InternetService"] == "Fiber optic"][TARGET] == "Yes").mean() * 100 if "InternetService" in df.columns else None
    electronic_churn = (df[df["PaymentMethod"] == "Electronic check"][TARGET] == "Yes").mean() * 100 if "PaymentMethod" in df.columns else None

    c1, c2, c3 = st.columns(3)
    c1.metric("Overall Churn Rate", f"{churn_rate:.1f}%")
    if mtm_churn is not None:
        c2.metric("Month-to-Month Churn", f"{mtm_churn:.1f}%")
    if two_yr_churn is not None:
        c3.metric("Two-Year Contract Churn", f"{two_yr_churn:.1f}%")

    st.write("")
    insights = []
    if mtm_churn is not None and two_yr_churn is not None:
        insights.append(
            f"**Contract length is the single biggest lever**: month-to-month customers churn at "
            f"**{mtm_churn:.1f}%**, versus just **{two_yr_churn:.1f}%** for two-year contracts. "
            "Incentivizing longer commitments (discounts, loyalty perks) could meaningfully cut churn."
        )
    if fiber_churn is not None:
        insights.append(
            f"**Fiber optic customers churn at {fiber_churn:.1f}%** — noticeably higher than other internet "
            "service types. This may point to reliability, pricing, or competitive pressure specific to fiber plans."
        )
    if electronic_churn is not None:
        insights.append(
            f"**Electronic check users show elevated churn ({electronic_churn:.1f}%)** compared to automatic "
            "payment methods — nudging customers toward autopay could improve retention and reduce friction."
        )
    insights.append(
        "**New customers are the highest-risk group** — churn is heavily concentrated in the first few months "
        "of tenure, suggesting an onboarding or early-engagement gap worth investing in."
    )

    for msg in insights:
        st.markdown(f'<div class="glass-card" style="margin-bottom:12px;">💡 {msg}</div>', unsafe_allow_html=True)

    with st.expander("📌 Recommended Next Actions"):
        st.checkbox("Launch a contract-upgrade incentive for month-to-month customers")
        st.checkbox("Investigate fiber optic service quality and pricing complaints")
        st.checkbox("Promote automatic payment enrollment")
        st.checkbox("Build a 90-day onboarding journey for new customers")


